import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.ZhLefgN8.js";const b=JSON.parse('{"title":"基金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/funds.md","filePath":"zh-CN/portfolio-and-statements/funds.md"}'),o={name:"portfolio-and-statements/funds.md"};function l(i,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="基金" tabindex="-1">基金 <a class="header-anchor" href="#基金" aria-label="Permalink to &quot;基金&quot;">​</a></h1><p>资产 Tab 的基金页展示账户内的基金持仓情况，并提供余额通增值计划的入口和管理功能。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>资产页 → 全部功能 → 基金，或持仓列表中切换至「基金」标签。</p><h2 id="持仓概览" tabindex="-1">持仓概览 <a class="header-anchor" href="#持仓概览" aria-label="Permalink to &quot;持仓概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>总市值</td><td>当前所有基金持仓折算后的总市值</td></tr><tr><td>持仓收益</td><td>当前浮动盈亏金额</td></tr><tr><td>累计收益</td><td>历史已实现与未实现收益合计</td></tr></tbody></table><blockquote><p>明细数据经四舍五入处理，与汇总数据可能存在细微偏差，请以结单数据为准。</p></blockquote><h2 id="快捷链接" tabindex="-1">快捷链接 <a class="header-anchor" href="#快捷链接" aria-label="Permalink to &quot;快捷链接&quot;">​</a></h2><ul><li><strong>交易记录</strong> — 查看基金买入/卖出历史</li><li><strong>基金盈亏</strong> — 查看各只基金的盈亏详情</li><li><strong>基金定投</strong> — 设置或管理定期定额投资计划</li></ul><h2 id="余额通增值计划" tabindex="-1">余额通增值计划 <a class="header-anchor" href="#余额通增值计划" aria-label="Permalink to &quot;余额通增值计划&quot;">​</a></h2><p>余额通是长桥的闲钱增值服务，将账户闲置现金自动申购货币市场基金，实现资金不闲置。</p><h3 id="主要特点" tabindex="-1">主要特点 <a class="header-anchor" href="#主要特点" aria-label="Permalink to &quot;主要特点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特点</th><th>说明</th></tr></thead><tbody><tr><td>自动申购</td><td>一次签约，闲置资金自动申购，无需手动操作</td></tr><tr><td>随时可用</td><td>支持随时手动赎回，最晚 T+1 日到账，赎回后可立即用于交易、出金或换汇；出金时系统自动赎回（1~2 个交易日），货币兑换或主动还款需手动赎回</td></tr><tr><td>低门槛</td><td>起购金额低，单账户无资金上限</td></tr><tr><td>低风险</td><td>主要投资流动性良好的货币市场基金</td></tr></tbody></table><h3 id="开通流程" tabindex="-1">开通流程 <a class="header-anchor" href="#开通流程" aria-label="Permalink to &quot;开通流程&quot;">​</a></h3><ol><li>点击「开通余额通」</li><li>阅读并同意相关协议（服务授权、基金销售协议、风险披露等）</li><li>完成签约，系统自动开始申购</li></ol><p>收益参考 7 日预期年化收益率，最终以实际到账金额为准，不保证最低收益。</p><blockquote><p>详细规则请参考<a href="/wiki/funds-and-wealth/余额通/香港余额通">余额通</a>。</p></blockquote>',17)])])}const p=a(o,[["render",l]]);export{b as __pageData,p as default};
